  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import {
  4	  DescriptionList,
  5	  DescriptionListDescription,
  6	  DescriptionListGroup,
  7	  DescriptionListTerm,
  8	} from '@patternfly/react-core';
  9	import {
 10	  taskRunFilterReducer,
 11	  taskRunFilterTitleReducer,
 12	} from '../../utils/pipeline-filter-reducer';
 13	import { TaskRunKind } from '../../../types';
 14	import { TektonResourceLabel } from '../../../consts';
 15	import { ResourceLink, Timestamp } from '@openshift-console/dynamic-plugin-sdk';
 16	import { getReferenceForModel } from '../../pipelines-overview/utils';
 17	import { PipelineRunModel, PodModel } from '../../../models';
 18	import { pipelineRunDuration } from '../../../components/utils/pipeline-utils';
 19	import RunDetailsErrorLog from '../../../components/logs/RunDetailsErrorLog';
 20	import { getTRLogSnippet } from '../taskRunLogSnippet';
 21	import Status from '../../status/Status';
 22	import WorkspaceResourceLinkList from '../../workspaces/WorkspaceResourceLinkList';
 23	import { useMultiClusterProxyService } from '../../hooks/useMultiClusterProxyService';
 24	
 25	export interface TaskRunDetailsStatusProps {
 26	  taskRun: TaskRunKind;
 27	}
 28	
 29	const TaskRunDetailsStatus: React.FC<TaskRunDetailsStatusProps> = ({
 30	  taskRun,
 31	}) => {
 32	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 33	  const {isResourceManagedByKueue} = useMultiClusterProxyService({ labels: taskRun?.metadata?.labels });
 34	  const pipelineRunName =
 35	    taskRun.metadata?.labels?.[TektonResourceLabel.pipelinerun];
 36	
 37	  return (
 38	    <DescriptionList>
 39	      <DescriptionListGroup>
 40	        <DescriptionListTerm>{t('Status')}</DescriptionListTerm>
 41	        <DescriptionListDescription>
 42	          <Status
 43	            status={taskRunFilterReducer(taskRun)}
 44	            title={taskRunFilterTitleReducer(taskRun)}
 45	          />
 46	        </DescriptionListDescription>
 47	      </DescriptionListGroup>
 48	      {taskRun.metadata?.labels?.[TektonResourceLabel.pipelinerun] && (
 49	        <DescriptionListGroup data-test="pipelineRun">
 50	          <DescriptionListTerm>{t('PipelineRun')}</DescriptionListTerm>
 51	          <DescriptionListDescription>
 52	            <ResourceLink
 53	              kind={getReferenceForModel(PipelineRunModel)}
 54	              name={taskRun.metadata.labels[TektonResourceLabel.pipelinerun]}
 55	              namespace={taskRun.metadata.namespace}
 56	            />
 57	          </DescriptionListDescription>
 58	        </DescriptionListGroup>
 59	      )}
 60	      <DescriptionListGroup>
 61	        <DescriptionListTerm>{t('Started')}</DescriptionListTerm>
 62	        <DescriptionListDescription>
 63	          <Timestamp timestamp={taskRun?.status?.startTime} />
 64	        </DescriptionListDescription>
 65	      </DescriptionListGroup>
 66	      <DescriptionListGroup>
 67	        <DescriptionListTerm>{t('Duration')}</DescriptionListTerm>
 68	        <DescriptionListDescription>
 69	          {pipelineRunDuration(taskRun)}
 70	        </DescriptionListDescription>
 71	      </DescriptionListGroup>
 72	      <RunDetailsErrorLog
 73	        logDetails={getTRLogSnippet(taskRun)}
 74	        namespace={taskRun.metadata?.namespace}
 75	        isResourceManagedByKueue={isResourceManagedByKueue}
 76	        pipelineRunName={pipelineRunName}
 77	      />
 78	      {taskRun?.status?.podName && (
 79	        <DescriptionListGroup data-test="pod">
 80	          <DescriptionListTerm>{t('Pod')}</DescriptionListTerm>
 81	          <DescriptionListDescription>
 82	            <ResourceLink
 83	              kind={PodModel.kind}
 84	              name={taskRun.status.podName}
 85	              namespace={taskRun.metadata.namespace}
 86	            />
 87	          </DescriptionListDescription>
 88	        </DescriptionListGroup>
 89	      )}
 90	      <WorkspaceResourceLinkList
 91	        workspaces={taskRun.spec.workspaces}
 92	        namespace={taskRun.metadata.namespace}
 93	        ownerResourceName={taskRun.metadata.name}
 94	        ownerResourceKind={taskRun.kind}
 95	      />
 96	    </DescriptionList>
 97	  );
 98	};
 99	
100	export default TaskRunDetailsStatus;

